/* CISSP :: content/quiz8.js — CISSP Domain 8 question bank (100 items). */
window.CISSP = window.CISSP || {}; CISSP.questions = CISSP.questions || [];
CISSP.questions.push(
  {"id":"D8-001","domain":8,"obj":"8.1","diff":"easy","q":"An organization builds software in strict sequential phases where each phase must fully complete and be signed off before the next begins, and requirements are frozen up front. Which SDLC methodology is this?","options":["Waterfall","Agile Scrum","DevSecOps","Spiral"],"answer":0,"explain":"<strong>Waterfall</strong> is a linear, phase-gated model where requirements, design, implementation, testing, and deployment happen sequentially with formal sign-off between stages and frozen up-front requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Agile Scrum</b>: Scrum is iterative and welcomes changing requirements across short sprints, the opposite of frozen phases.</span><span class='qd'><b>DevSecOps</b>: DevSecOps is a continuous, automated integration-of-security culture, not a sequential phase-gated model.</span><span class='qd'><b>Spiral</b>: Spiral is risk-driven and iterative with repeated prototyping cycles, not a strict one-pass linear flow.</span>"},
  {"id":"D8-002","domain":8,"obj":"8.1","diff":"medium","q":"A product team must deliver software for a life-critical medical device where requirements are stable, regulatory documentation is exhaustive, and every phase needs formal traceability. Which methodology BEST fits?","options":["Extreme Programming (XP)","Kanban with no upfront planning","Rapid Application Development (RAD)","Waterfall"],"answer":3,"explain":"<strong>Waterfall</strong> suits stable requirements and heavy regulatory documentation because its phase gates produce the formal traceability and sign-off records regulators demand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Extreme Programming (XP)</b>: XP optimizes for rapidly changing requirements and lightweight documentation, a poor fit for exhaustive regulatory traceability.</span><span class='qd'><b>Kanban with no upfront planning</b>: continuous flow without upfront planning undermines the fixed, documented requirements a medical device certification requires.</span><span class='qd'><b>Rapid Application Development (RAD)</b>: RAD emphasizes speed and prototyping over the rigorous documentation life-critical certification needs.</span>"},
  {"id":"D8-003","domain":8,"obj":"8.1","diff":"medium","q":"A development organization wants security integrated continuously into automated build and deployment pipelines, with security testing 'shifted left' and treated as everyone's responsibility. Which approach describes this?","options":["DevSecOps","Waterfall with a final penetration test","Big-bang integration","V-model only"],"answer":0,"explain":"<strong>DevSecOps</strong> embeds security throughout the CI/CD pipeline, shifts testing left, and makes security a shared responsibility rather than a late-stage gate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Waterfall with a final penetration test</b>: a single late pen test is the opposite of continuous shift-left security.</span><span class='qd'><b>Big-bang integration</b>: big-bang integration is a testing strategy where components are combined all at once, not a security-integration philosophy.</span><span class='qd'><b>V-model only</b>: the V-model pairs test phases to development phases but does not describe continuous automated security in pipelines.</span>"},
  {"id":"D8-004","domain":8,"obj":"8.1","diff":"easy","q":"In Scrum, what is the fixed-length iteration during which a potentially shippable product increment is produced?","options":["A sprint","A milestone","A waterfall phase","A change advisory board window"],"answer":0,"explain":"<strong>A sprint</strong> is Scrum's time-boxed iteration (commonly 1-4 weeks) that yields a potentially shippable increment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A milestone</b>: a milestone is a project checkpoint, not the recurring time-boxed iteration Scrum defines.</span><span class='qd'><b>A waterfall phase</b>: waterfall phases are sequential stages, not iterative increments.</span><span class='qd'><b>A change advisory board window</b>: a CAB reviews changes in ITIL; it is not a Scrum development iteration.</span>"},
  {"id":"D8-005","domain":8,"obj":"8.1","diff":"hard","q":"A CISO wants to measure and improve the organization's software-security practices over time using a framework organized into business functions such as Governance, Design, Implementation, and Verification. Which maturity model is designed specifically for software assurance?","options":["ITIL","COBIT","OWASP SAMM","ISO 9001"],"answer":2,"explain":"<strong>OWASP SAMM</strong> (Software Assurance Maturity Model) is purpose-built to assess and improve software security across business functions like Governance, Design, Implementation, and Verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ITIL</b>: ITIL is an IT service-management framework, not a software-security maturity model.</span><span class='qd'><b>COBIT</b>: COBIT is an IT governance framework and does not specifically model software-security maturity.</span><span class='qd'><b>ISO 9001</b>: ISO 9001 addresses general quality management, not software security assurance maturity.</span>"},
  {"id":"D8-006","domain":8,"obj":"8.1","diff":"medium","q":"An organization is assessed at CMMI Level 1. What does this maturity level indicate about its processes?","options":["Processes are initial, ad hoc, and often chaotic and dependent on individual heroics","Processes are quantitatively managed and predictable","Processes are defined and standardized organization-wide","Processes are continuously optimized"],"answer":0,"explain":"<strong>Processes are initial, ad hoc, and often chaotic and dependent on individual heroics</strong> describes CMMI Level 1 (Initial), where success is unpredictable and relies on individuals rather than repeatable process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Processes are quantitatively managed and predictable</b>: that describes Level 4 (Quantitatively Managed).</span><span class='qd'><b>Processes are defined and standardized organization-wide</b>: that describes Level 3 (Defined).</span><span class='qd'><b>Processes are continuously optimized</b>: that describes Level 5 (Optimizing), the highest maturity.</span>"},
  {"id":"D8-007","domain":8,"obj":"8.1","diff":"medium","q":"During which SDLC phase should security requirements FIRST be formally captured to be most cost-effective?","options":["During the coding phase","During user acceptance testing","During the requirements/initiation phase","During post-deployment operations"],"answer":2,"explain":"<strong>During the requirements/initiation phase</strong> security requirements should be defined first, because defects and missing controls are cheapest to address before design and code commit to them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>During the coding phase</b>: waiting until coding means design decisions are already locked, raising remediation cost.</span><span class='qd'><b>During user acceptance testing</b>: UAT is far too late to introduce fundamental security requirements economically.</span><span class='qd'><b>During post-deployment operations</b>: adding requirements after release is the most expensive and disruptive point.</span>"},
  {"id":"D8-008","domain":8,"obj":"8.1","diff":"easy","q":"What is the PRIMARY purpose of a software Configuration Management (CM) process in the SDLC?","options":["To identify, control, and track changes to software artifacts and their versions","To write marketing documentation","To hire developers","To design the user interface"],"answer":0,"explain":"<strong>To identify, control, and track changes to software artifacts and their versions</strong> is the core aim of configuration management, ensuring integrity and reproducibility of builds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To write marketing documentation</b>: marketing is unrelated to controlling software artifacts.</span><span class='qd'><b>To hire developers</b>: staffing is a human-resources activity, not configuration management.</span><span class='qd'><b>To design the user interface</b>: UI design is a development activity, not change control over artifacts.</span>"},
  {"id":"D8-009","domain":8,"obj":"8.1","diff":"hard","q":"A team practices DevOps with rapid daily releases but security reviews create a bottleneck because they are performed manually at the end. What is the BEST way to preserve security without slowing delivery?","options":["Stop doing security reviews to keep velocity","Move all releases to a quarterly manual schedule","Have developers self-attest that code is secure with no tooling","Automate security testing (SAST, dependency scanning, IaC scanning) into the pipeline as gated stages"],"answer":3,"explain":"<strong>Automate security testing (SAST, dependency scanning, IaC scanning) into the pipeline as gated stages</strong> transforms DevOps into DevSecOps, keeping velocity while enforcing security consistently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stop doing security reviews to keep velocity</b>: abandoning security to preserve speed trades away the organization's risk posture.</span><span class='qd'><b>Move all releases to a quarterly manual schedule</b>: this destroys the delivery cadence DevOps exists to provide.</span><span class='qd'><b>Have developers self-attest with no tooling</b>: unverified self-attestation provides no assurance and invites unchecked vulnerabilities.</span>"},
  {"id":"D8-010","domain":8,"obj":"8.1","diff":"medium","q":"Which statement BEST distinguishes the Agile Manifesto's values from a traditional plan-driven approach?","options":["Agile values working software and responding to change over rigid plans and heavy documentation","Agile values comprehensive documentation over working software","Agile forbids any planning or design","Agile values contract negotiation over customer collaboration"],"answer":0,"explain":"<strong>Agile values working software and responding to change over rigid plans and heavy documentation</strong> captures the Manifesto, which prizes adaptability and delivered value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Agile values comprehensive documentation over working software</b>: this reverses the Manifesto, which favors working software.</span><span class='qd'><b>Agile forbids any planning or design</b>: Agile still plans and designs, just iteratively; it does not forbid them.</span><span class='qd'><b>Agile values contract negotiation over customer collaboration</b>: the Manifesto explicitly favors customer collaboration over contract negotiation.</span>"},
  {"id":"D8-011","domain":8,"obj":"8.1","diff":"medium","q":"The Spiral model is characterized by which distinguishing feature compared with Waterfall?","options":["It has no testing phase","It freezes requirements permanently at the start","Each iteration includes an explicit risk-analysis activity and prototyping","It eliminates documentation entirely"],"answer":2,"explain":"<strong>Each iteration includes an explicit risk-analysis activity and prototyping</strong> is the defining trait of the risk-driven Spiral model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It has no testing phase</b>: Spiral includes testing within each cycle.</span><span class='qd'><b>It freezes requirements permanently at the start</b>: that is Waterfall's trait, not Spiral's iterative refinement.</span><span class='qd'><b>It eliminates documentation entirely</b>: Spiral produces documentation across its cycles; it does not remove it.</span>"},
  {"id":"D8-012","domain":8,"obj":"8.1","diff":"easy","q":"In Scrum, who is responsible for maximizing the value of the product and managing the product backlog?","options":["The Scrum Master","The penetration tester","The Product Owner","The release manager"],"answer":2,"explain":"<strong>The Product Owner</strong> owns and prioritizes the product backlog and is accountable for maximizing the product's value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The Scrum Master</b>: the Scrum Master facilitates the process and removes impediments, not backlog value ownership.</span><span class='qd'><b>The penetration tester</b>: a pen tester assesses security and is not a defined Scrum role.</span><span class='qd'><b>The release manager</b>: release management coordinates deployment, not backlog prioritization in Scrum.</span>"},
  {"id":"D8-013","domain":8,"obj":"8.1","diff":"hard","q":"An organization wants a formal, industry-recognized appraisal of its process maturity to win government contracts that require a specific maturity rating. Which model provides staged appraisal levels 1 through 5 for this purpose?","options":["OWASP Top 10","CMMI","STRIDE","MITRE ATT&CK"],"answer":1,"explain":"<strong>CMMI</strong> (Capability Maturity Model Integration) provides staged maturity levels 1-5 with formal appraisals often referenced in government contracting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>OWASP Top 10</b>: the OWASP Top 10 is an awareness list of web risks, not a process-maturity appraisal model.</span><span class='qd'><b>STRIDE</b>: STRIDE is a threat-modeling taxonomy, not a maturity rating.</span><span class='qd'><b>MITRE ATT&CK</b>: ATT&CK catalogs adversary techniques, not organizational process maturity.</span>"},
  {"id":"D8-014","domain":8,"obj":"8.1","diff":"medium","q":"A security architect is embedded in an Agile team and wants threat modeling to keep pace with iterative development. What is the BEST integration approach?","options":["Perform one large threat model at project start and never revisit it","Skip threat modeling because Agile moves too fast","Outsource threat modeling to a vendor after release","Threat-model incrementally each sprint as new features and attack surface are added"],"answer":3,"explain":"<strong>Threat-model incrementally each sprint as new features and attack surface are added</strong> keeps threat modeling continuous and aligned with evolving design, matching Agile's cadence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Perform one large threat model at project start and never revisit it</b>: a single upfront model becomes stale as the design changes across sprints.</span><span class='qd'><b>Skip threat modeling because Agile moves too fast</b>: skipping it leaves new attack surface unexamined.</span><span class='qd'><b>Outsource threat modeling to a vendor after release</b>: modeling after release is too late to influence secure design.</span>"},
  {"id":"D8-015","domain":8,"obj":"8.1","diff":"easy","q":"What is a software 'change control' board (CCB) primarily responsible for?","options":["Reviewing, approving, or rejecting proposed changes to controlled software baselines","Writing all the source code","Marketing the product","Provisioning developer laptops"],"answer":0,"explain":"<strong>Reviewing, approving, or rejecting proposed changes to controlled software baselines</strong> is the CCB's role, ensuring changes are authorized and assessed for impact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Writing all the source code</b>: coding is the developers' job, not the board's.</span><span class='qd'><b>Marketing the product</b>: marketing is unrelated to change authorization.</span><span class='qd'><b>Provisioning developer laptops</b>: IT provisioning is an operations task, not change control.</span>"},
  {"id":"D8-016","domain":8,"obj":"8.1","diff":"medium","q":"Which pairing correctly matches the maturity model to what it primarily measures?","options":["SAMM measures generic manufacturing quality; CMMI measures only web-app risk","Both SAMM and CMMI measure only network uptime","CMMI measures OWASP Top 10 coverage only","CMMI measures general process maturity; OWASP SAMM measures software-security assurance maturity"],"answer":3,"explain":"<strong>CMMI measures general process maturity; OWASP SAMM measures software-security assurance maturity</strong> correctly distinguishes the two models' focus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAMM measures generic manufacturing quality; CMMI measures only web-app risk</b>: this misattributes both models' purposes.</span><span class='qd'><b>Both SAMM and CMMI measure only network uptime</b>: neither model measures uptime.</span><span class='qd'><b>CMMI measures OWASP Top 10 coverage only</b>: CMMI is process maturity, not a checklist of web risks.</span>"},
  {"id":"D8-017","domain":8,"obj":"8.1","diff":"hard","q":"A DevSecOps transformation is stalling because developers view security as 'the security team's problem.' From a CISSP governance perspective, what is the MOST effective corrective action?","options":["Add more manual security gates at the end of the pipeline","Remove developers' pipeline access","Replace all developers","Establish shared security accountability with training, security champions, and metrics tied to team objectives"],"answer":3,"explain":"<strong>Establish shared security accountability with training, security champions, and metrics tied to team objectives</strong> addresses the cultural root cause central to DevSecOps success.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more manual security gates at the end of the pipeline</b>: late manual gates reinforce the very silo mentality causing the stall.</span><span class='qd'><b>Remove developers' pipeline access</b>: removing access punishes the team and blocks the shared ownership DevSecOps needs.</span><span class='qd'><b>Replace all developers</b>: wholesale replacement is impractical and does not fix the cultural process.</span>"},
  {"id":"D8-018","domain":8,"obj":"8.1","diff":"medium","q":"In the V-model, verification/validation test activities are planned in parallel with which development activities?","options":["In parallel with their corresponding requirements and design phases","Only after all coding is finished","Only during production incidents","Never; the V-model has no testing"],"answer":0,"explain":"<strong>In parallel with their corresponding requirements and design phases</strong> is the V-model's hallmark: each development phase has a matching test phase defined at the same time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only after all coding is finished</b>: the V-model plans test phases upfront, not solely after coding.</span><span class='qd'><b>Only during production incidents</b>: incident handling is operations, not the V-model's planned test mapping.</span><span class='qd'><b>Never; the V-model has no testing</b>: testing is central to the V-model.</span>"},
  {"id":"D8-019","domain":8,"obj":"8.1","diff":"easy","q":"What does 'shift left' mean in secure software development?","options":["Deploying only on the left half of the data center","Moving security activities earlier in the SDLC","Writing code right to left","Moving all testing to production"],"answer":1,"explain":"<strong>Moving security activities earlier in the SDLC</strong> is the meaning of shift left, catching defects sooner when they are cheaper to fix.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deploying only on the left half of the data center</b>: this is a nonsensical physical interpretation.</span><span class='qd'><b>Writing code right to left</b>: shift left is about timing of activities, not text direction.</span><span class='qd'><b>Moving all testing to production</b>: that is shifting right, the opposite of shift left.</span>"},
  {"id":"D8-020","domain":8,"obj":"8.1","diff":"medium","q":"An organization uses Kanban to manage development work. Which principle is MOST central to Kanban?","options":["Fixed-length time-boxed sprints","Freezing all requirements at project start","Visualizing workflow and limiting work in progress (WIP)","Eliminating any feedback loops"],"answer":2,"explain":"<strong>Visualizing workflow and limiting work in progress (WIP)</strong> is Kanban's central practice, promoting continuous flow and exposing bottlenecks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fixed-length time-boxed sprints</b>: sprints are a Scrum construct; Kanban uses continuous flow, not fixed iterations.</span><span class='qd'><b>Freezing all requirements at project start</b>: that is a Waterfall trait, contrary to Kanban's flexibility.</span><span class='qd'><b>Eliminating any feedback loops</b>: Kanban relies on feedback to improve flow, not eliminate it.</span>"},
  {"id":"D8-021","domain":8,"obj":"8.1","diff":"hard","q":"A regulated bank must adopt Agile but also satisfy auditors who require documented approvals and traceability. What is the BEST reconciliation of these needs?","options":["Abandon Agile and revert fully to Waterfall","Use a hybrid (e.g., scaled Agile) that keeps iterative delivery while embedding required governance gates and traceable records","Ignore the auditors","Only document after the software is retired"],"answer":1,"explain":"<strong>Use a hybrid (e.g., scaled Agile) that keeps iterative delivery while embedding required governance gates and traceable records</strong> lets the bank gain Agile speed and satisfy audit and traceability obligations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Abandon Agile and revert fully to Waterfall</b>: reverting discards Agile's benefits when a hybrid can satisfy both goals.</span><span class='qd'><b>Ignore the auditors</b>: ignoring regulatory audit requirements exposes the bank to compliance failure.</span><span class='qd'><b>Only document after the software is retired</b>: post-retirement documentation cannot satisfy in-flight audit traceability.</span>"},
  {"id":"D8-022","domain":8,"obj":"8.1","diff":"medium","q":"What is the PRIMARY security benefit of maintaining a software baseline in configuration management?","options":["It guarantees the software is bug-free","It removes the need for testing","It provides a known-good reference so unauthorized or unexpected changes can be detected","It automatically encrypts all traffic"],"answer":2,"explain":"<strong>It provides a known-good reference so unauthorized or unexpected changes can be detected</strong> is the security value of a baseline, supporting integrity monitoring and rollback.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the software is bug-free</b>: a baseline records a configuration; it cannot guarantee absence of bugs.</span><span class='qd'><b>It removes the need for testing</b>: baselines do not replace testing.</span><span class='qd'><b>It automatically encrypts all traffic</b>: encryption is unrelated to configuration baselining.</span>"},
  {"id":"D8-023","domain":8,"obj":"8.1","diff":"easy","q":"Which Scrum event is a short daily meeting for the team to synchronize and surface impediments?","options":["The sprint retrospective","The change advisory board","The steering committee","The daily standup (daily Scrum)"],"answer":3,"explain":"<strong>The daily standup (daily Scrum)</strong> is the brief daily synchronization meeting where the team coordinates work and raises blockers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The sprint retrospective</b>: the retrospective happens at sprint end to reflect on process, not daily.</span><span class='qd'><b>The change advisory board</b>: a CAB is an ITIL change-review body, not a Scrum event.</span><span class='qd'><b>The steering committee</b>: a steering committee is a governance body, not a daily team sync.</span>"},
  {"id":"D8-024","domain":8,"obj":"8.1","diff":"medium","q":"A CISO is choosing where to invest to raise the organization from CMMI Level 2 to Level 3. What characterizes the transition to Level 3 (Defined)?","options":["Moving from optimizing back to ad hoc processes","Standardizing and documenting processes organization-wide rather than only at the project level","Eliminating all measurement","Removing all documentation"],"answer":1,"explain":"<strong>Standardizing and documenting processes organization-wide rather than only at the project level</strong> characterizes CMMI Level 3, where tailored organizational standards replace project-by-project processes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Moving from optimizing back to ad hoc processes</b>: maturity progresses forward, not backward to ad hoc.</span><span class='qd'><b>Eliminating all measurement</b>: measurement increases at higher levels; Level 4 adds quantitative management.</span><span class='qd'><b>Removing all documentation</b>: Level 3 increases documentation and standardization, not removes it.</span>"},
  {"id":"D8-025","domain":8,"obj":"8.2","diff":"easy","q":"Which type of testing analyzes source code without executing the program to find vulnerabilities?","options":["Dynamic Application Security Testing (DAST)","Static Application Security Testing (SAST)","Load testing","Usability testing"],"answer":1,"explain":"<strong>Static Application Security Testing (SAST)</strong> inspects source code, bytecode, or binaries without running the application, using white-box analysis to flag insecure patterns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Dynamic Application Security Testing (DAST)</b>: DAST tests a running application from the outside, so it executes the program.</span><span class='qd'><b>Load testing</b>: load testing measures performance under demand, not code security.</span><span class='qd'><b>Usability testing</b>: usability testing evaluates user experience, not vulnerabilities.</span>"},
  {"id":"D8-026","domain":8,"obj":"8.2","diff":"easy","q":"Which testing approach probes a running application from the outside, sending inputs and observing responses to find vulnerabilities without access to source code?","options":["SAST","Code review","DAST","Unit testing"],"answer":2,"explain":"<strong>DAST</strong> (Dynamic Application Security Testing) is black-box testing that interacts with the live application to detect vulnerabilities such as injection and misconfiguration at runtime.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST</b>: SAST analyzes code statically without running it, the opposite of DAST.</span><span class='qd'><b>Code review</b>: code review is a manual/static inspection of source, not runtime probing.</span><span class='qd'><b>Unit testing</b>: unit testing verifies functional correctness of code units, not runtime security probing of a deployed app.</span>"},
  {"id":"D8-027","domain":8,"obj":"8.2","diff":"medium","q":"A security team wants to detect a SQL injection flaw that only manifests when the app is deployed with its real database and runtime configuration. Which testing type is BEST suited?","options":["SAST","DAST","A spell-checker","License scanning"],"answer":1,"explain":"<strong>DAST</strong> exercises the deployed, running application with live configuration, making it well suited to confirm injection flaws that depend on runtime behavior.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST</b>: SAST may flag the pattern but cannot confirm exploitation against the real runtime and database.</span><span class='qd'><b>A spell-checker</b>: a spell-checker has nothing to do with security testing.</span><span class='qd'><b>License scanning</b>: license scanning checks open-source license compliance, not injection vulnerabilities.</span>"},
  {"id":"D8-028","domain":8,"obj":"8.2","diff":"medium","q":"Which is a KEY advantage of SAST over DAST?","options":["SAST requires the application to be fully deployed and running","SAST can be run early on incomplete code and pinpoints the exact vulnerable line","SAST never produces false positives","SAST tests business logic exactly as an attacker would at runtime"],"answer":1,"explain":"<strong>SAST can be run early on incomplete code and pinpoints the exact vulnerable line</strong> is a core SAST advantage, enabling shift-left detection with precise remediation location.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST requires the application to be fully deployed and running</b>: that describes DAST; SAST needs no running app.</span><span class='qd'><b>SAST never produces false positives</b>: SAST is actually prone to false positives.</span><span class='qd'><b>SAST tests business logic exactly as an attacker would at runtime</b>: runtime attacker emulation is DAST's strength, not SAST's.</span>"},
  {"id":"D8-029","domain":8,"obj":"8.2","diff":"hard","q":"An organization wants runtime detection that instruments the application itself to observe data flow and block attacks from inside the app during execution. Which technology is this?","options":["SAST","IAST/RASP (interactive/runtime application self-protection)","A network firewall","A password manager"],"answer":1,"explain":"<strong>IAST/RASP (interactive/runtime application self-protection)</strong> instruments the application internally to observe execution and data flow, combining runtime visibility with the ability to block attacks in-process.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST</b>: SAST is static and does not instrument a running application.</span><span class='qd'><b>A network firewall</b>: a firewall filters network traffic and has no view into internal application execution.</span><span class='qd'><b>A password manager</b>: a password manager stores credentials and is unrelated to runtime application analysis.</span>"},
  {"id":"D8-030","domain":8,"obj":"8.2","diff":"easy","q":"What is the PRIMARY purpose of a version control system (repository) such as Git in a development ecosystem?","options":["To track changes to source code over time and enable collaboration and rollback","To render marketing videos","To scan networks for open ports","To encrypt email"],"answer":0,"explain":"<strong>To track changes to source code over time and enable collaboration and rollback</strong> is the core function of version control, providing history, branching, and integrity of code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To render marketing videos</b>: media rendering is unrelated to source control.</span><span class='qd'><b>To scan networks for open ports</b>: port scanning is a network-security task, not version control.</span><span class='qd'><b>To encrypt email</b>: email encryption is a messaging-security function, not repository management.</span>"},
  {"id":"D8-031","domain":8,"obj":"8.2","diff":"medium","q":"A developer accidentally committed an AWS secret key to a public Git repository. What is the BEST immediate response?","options":["Delete the commit message only and assume it is safe","Do nothing because it is only in the commit history","Make the repository private next month","Immediately revoke/rotate the exposed key and then purge it from history"],"answer":3,"explain":"<strong>Immediately revoke/rotate the exposed key and then purge it from history</strong> is correct because once a secret is public it must be treated as compromised and invalidated first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the commit message only and assume it is safe</b>: editing a message does not remove the leaked key from history or from anyone who already cloned it.</span><span class='qd'><b>Do nothing because it is only in the commit history</b>: history is readable, so the key is fully exposed and must be rotated.</span><span class='qd'><b>Make the repository private next month</b>: a delayed privacy change ignores that the key is already compromised now.</span>"},
  {"id":"D8-032","domain":8,"obj":"8.2","diff":"medium","q":"Which control BEST prevents secrets such as API keys and passwords from being hard-coded and committed into source repositories?","options":["Disabling all logging","Emailing secrets to the team","Storing secrets in plaintext config files in the repo","Using a secrets manager plus automated pre-commit secret scanning in the pipeline"],"answer":3,"explain":"<strong>Using a secrets manager plus automated pre-commit secret scanning in the pipeline</strong> both externalizes secrets and catches accidental commits before they land.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling all logging</b>: turning off logging harms detection and does nothing to prevent hard-coded secrets.</span><span class='qd'><b>Emailing secrets to the team</b>: email distribution spreads secrets insecurely and does not stop repo commits.</span><span class='qd'><b>Storing secrets in plaintext config files in the repo</b>: this is exactly the insecure practice to avoid.</span>"},
  {"id":"D8-033","domain":8,"obj":"8.2","diff":"hard","q":"An attacker compromises a build server and injects malicious code that is signed and shipped to all customers through the normal pipeline. This is BEST described as which type of attack?","options":["A phishing attack","A software supply-chain (CI/CD pipeline) attack","A brute-force attack","A social-engineering vishing attack"],"answer":1,"explain":"<strong>A software supply-chain (CI/CD pipeline) attack</strong> describes compromising the build/distribution process so trusted, signed artifacts carry malicious code to downstream consumers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A phishing attack</b>: phishing tricks users via deceptive messages; it is not the pipeline-compromise described.</span><span class='qd'><b>A brute-force attack</b>: brute force guesses credentials and does not describe injecting code into a build pipeline.</span><span class='qd'><b>A social-engineering vishing attack</b>: vishing is voice-based deception, unrelated to compromising a build server.</span>"},
  {"id":"D8-034","domain":8,"obj":"8.2","diff":"medium","q":"To ensure integrity of build artifacts so customers can verify they were produced by the legitimate pipeline and not tampered with, an organization should PRIMARILY implement:","options":["Code signing of build artifacts with protected keys","Larger font sizes in the README","More marketing emails","Disabling the pipeline"],"answer":0,"explain":"<strong>Code signing of build artifacts with protected keys</strong> lets consumers cryptographically verify origin and integrity of what they download.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Larger font sizes in the README</b>: documentation styling has no bearing on artifact integrity.</span><span class='qd'><b>More marketing emails</b>: marketing does not provide cryptographic integrity assurance.</span><span class='qd'><b>Disabling the pipeline</b>: disabling delivery is not a control for verifying artifact integrity.</span>"},
  {"id":"D8-035","domain":8,"obj":"8.2","diff":"easy","q":"What does CI/CD stand for in modern development pipelines?","options":["Compiled Instructions / Compiled Data","Central Index / Central Directory","Continuous Integration / Continuous Delivery (or Deployment)","Cryptographic Input / Cryptographic Decryption"],"answer":2,"explain":"<strong>Continuous Integration / Continuous Delivery (or Deployment)</strong> is the meaning of CI/CD, automating merge, build, test, and release.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compiled Instructions / Compiled Data</b>: this is not what the acronym denotes.</span><span class='qd'><b>Central Index / Central Directory</b>: these are unrelated invented expansions.</span><span class='qd'><b>Cryptographic Input / Cryptographic Decryption</b>: cryptography terms do not define CI/CD.</span>"},
  {"id":"D8-036","domain":8,"obj":"8.2","diff":"medium","q":"Which practice enforces that no single developer can merge code to the production branch without independent review?","options":["Direct commits to main with no checks","Giving every user administrator rights","Mandatory peer code review via protected-branch pull requests","Disabling branch protection"],"answer":2,"explain":"<strong>Mandatory peer code review via protected-branch pull requests</strong> enforces separation of duties and a second set of eyes before code reaches production.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Direct commits to main with no checks</b>: unrestricted direct commits bypass review entirely.</span><span class='qd'><b>Giving every user administrator rights</b>: broad admin rights weaken control rather than enforce review.</span><span class='qd'><b>Disabling branch protection</b>: removing protection eliminates the very control being sought.</span>"},
  {"id":"D8-037","domain":8,"obj":"8.2","diff":"hard","q":"A CISSP is designing pipeline security. Which control set BEST reduces the risk that a compromised third-party dependency introduces a vulnerability into the build?","options":["Allowing any public package at build time with no scanning","Software composition analysis (SCA) plus a curated internal artifact repository and pinned, verified versions","Removing all logging from the build","Turning off dependency management entirely"],"answer":1,"explain":"<strong>Software composition analysis (SCA) plus a curated internal artifact repository and pinned, verified versions</strong> combines vulnerability detection with provenance control over dependencies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allowing any public package at build time with no scanning</b>: unrestricted, unscanned packages maximize supply-chain risk.</span><span class='qd'><b>Removing all logging from the build</b>: removing logging hurts detection and does not address dependency risk.</span><span class='qd'><b>Turning off dependency management entirely</b>: abandoning dependency management increases, not reduces, risk.</span>"},
  {"id":"D8-038","domain":8,"obj":"8.2","diff":"medium","q":"What is the security purpose of scanning Infrastructure as Code (IaC) templates in the pipeline?","options":["To detect misconfigurations (e.g., public storage buckets, open security groups) before infrastructure is provisioned","To improve website fonts","To translate code to another language","To measure developer typing speed"],"answer":0,"explain":"<strong>To detect misconfigurations (e.g., public storage buckets, open security groups) before infrastructure is provisioned</strong> is the goal of IaC scanning, catching insecure infrastructure definitions early.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To improve website fonts</b>: fonts are unrelated to infrastructure security.</span><span class='qd'><b>To translate code to another language</b>: IaC scanning inspects configuration security, not language translation.</span><span class='qd'><b>To measure developer typing speed</b>: productivity metrics are irrelevant to IaC security scanning.</span>"},
  {"id":"D8-039","domain":8,"obj":"8.2","diff":"medium","q":"A build pipeline uses a shared service account with broad permissions for all jobs. What is the BEST improvement from a least-privilege standpoint?","options":["Give the account full domain admin to reduce failures","Issue scoped, short-lived credentials per pipeline stage limited to only what that stage needs","Share the credential in a public wiki","Disable authentication for the pipeline"],"answer":1,"explain":"<strong>Issue scoped, short-lived credentials per pipeline stage limited to only what that stage needs</strong> applies least privilege and limits blast radius if a stage is compromised.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Give the account full domain admin to reduce failures</b>: granting more privilege worsens risk, the opposite of least privilege.</span><span class='qd'><b>Share the credential in a public wiki</b>: publishing credentials is a severe exposure.</span><span class='qd'><b>Disable authentication for the pipeline</b>: removing authentication eliminates access control entirely.</span>"},
  {"id":"D8-040","domain":8,"obj":"8.2","diff":"hard","q":"An organization wants both broad runtime coverage and precise source-level detection in its pipeline. What is the BEST strategy regarding SAST and DAST?","options":["Use only SAST because DAST is redundant","Use only DAST because SAST is redundant","Use neither and rely on manual inspection only","Use SAST and DAST together as complementary controls, since each finds classes of issues the other misses"],"answer":3,"explain":"<strong>Use SAST and DAST together as complementary controls, since each finds classes of issues the other misses</strong> reflects that static and dynamic testing cover different vulnerability classes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use only SAST because DAST is redundant</b>: SAST misses runtime/config issues DAST catches, so it is not redundant.</span><span class='qd'><b>Use only DAST because SAST is redundant</b>: DAST misses source-level issues and lacks exact code location, so SAST adds value.</span><span class='qd'><b>Use neither and rely on manual inspection only</b>: manual-only inspection does not scale and misses much automated tools catch.</span>"},
  {"id":"D8-041","domain":8,"obj":"8.2","diff":"medium","q":"Why is it important that pipeline logs and build records be tamper-evident and retained?","options":["To make builds slower on purpose","To increase storage costs","To hide who made changes","To support forensic investigation and prove the integrity of what was built and by whom"],"answer":3,"explain":"<strong>To support forensic investigation and prove the integrity of what was built and by whom</strong> is why tamper-evident, retained pipeline logs matter for accountability and incident response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make builds slower on purpose</b>: logging is not intended to degrade performance.</span><span class='qd'><b>To increase storage costs</b>: cost is a side effect, not the purpose.</span><span class='qd'><b>To hide who made changes</b>: the opposite is true; logs establish accountability, not concealment.</span>"},
  {"id":"D8-042","domain":8,"obj":"8.2","diff":"easy","q":"Which type of scanning specifically inventories open-source components and flags known vulnerable versions (CVEs)?","options":["Load testing","A/B testing","Accessibility testing","Software Composition Analysis (SCA)"],"answer":3,"explain":"<strong>Software Composition Analysis (SCA)</strong> inventories third-party and open-source components and matches them against known-vulnerability databases like the NVD.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Load testing</b>: load testing measures performance under demand, not component vulnerabilities.</span><span class='qd'><b>A/B testing</b>: A/B testing compares user-experience variants, not vulnerable dependencies.</span><span class='qd'><b>Accessibility testing</b>: accessibility testing checks usability for people with disabilities, not CVEs.</span>"},
  {"id":"D8-043","domain":8,"obj":"8.2","diff":"medium","q":"A team's CI runs SAST on every pull request but developers ignore the findings because the tool floods them with low-value alerts. What is the BEST governance response?","options":["Turn SAST off entirely","Ignore all security findings by policy","Tune and prioritize rules, triage false positives, and fail the build only on confirmed high-severity issues","Require every finding be fixed before any development continues, regardless of validity"],"answer":2,"explain":"<strong>Tune and prioritize rules, triage false positives, and fail the build only on confirmed high-severity issues</strong> restores signal-to-noise so developers act on findings that matter.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Turn SAST off entirely</b>: disabling the control removes valuable detection instead of fixing tuning.</span><span class='qd'><b>Ignore all security findings by policy</b>: a policy to ignore findings abandons security assurance.</span><span class='qd'><b>Require every finding be fixed before any development continues, regardless of validity</b>: forcing fixes for false positives wastes effort and stalls delivery.</span>"},
  {"id":"D8-044","domain":8,"obj":"8.2","diff":"hard","q":"To reduce risk that developer workstations become the weak link that compromises the code repository, which control is MOST directly effective?","options":["Allowing anonymous pushes","Disabling all endpoint protection","Enforcing signed commits and MFA-protected, hardened access to the repository","Sharing one login for the whole team"],"answer":2,"explain":"<strong>Enforcing signed commits and MFA-protected, hardened access to the repository</strong> ties changes to verified identities and resists credential theft from a compromised endpoint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allowing anonymous pushes</b>: anonymous pushes destroy accountability and invite malicious commits.</span><span class='qd'><b>Disabling all endpoint protection</b>: removing endpoint defenses increases the very risk in question.</span><span class='qd'><b>Sharing one login for the whole team</b>: shared logins eliminate attribution and weaken access control.</span>"},
  {"id":"D8-045","domain":8,"obj":"8.2","diff":"medium","q":"What is the security value of an integrated development environment (IDE) plugin that flags insecure patterns as the developer types?","options":["It slows typing to reduce output","It provides immediate shift-left feedback so flaws are fixed before commit","It replaces the need for any pipeline testing","It encrypts the source at rest automatically"],"answer":1,"explain":"<strong>It provides immediate shift-left feedback so flaws are fixed before commit</strong> is the value of IDE security plugins, catching issues at the earliest and cheapest point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It slows typing to reduce output</b>: the goal is fast feedback, not reduced productivity.</span><span class='qd'><b>It replaces the need for any pipeline testing</b>: IDE feedback complements but does not replace pipeline gates.</span><span class='qd'><b>It encrypts the source at rest automatically</b>: encryption at rest is a storage control, not what an in-IDE linter does.</span>"},
  {"id":"D8-046","domain":8,"obj":"8.2","diff":"easy","q":"Which repository practice provides the ability to roll back to a previous known-good state after a bad change?","options":["Deleting all history","Committing directly to production with no records","Maintaining version history and tagged releases in source control","Storing code only on one developer's laptop"],"answer":2,"explain":"<strong>Maintaining version history and tagged releases in source control</strong> enables reliable rollback to a prior good state when a change causes problems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deleting all history</b>: deleting history removes the very records needed to roll back.</span><span class='qd'><b>Committing directly to production with no records</b>: no records means no recoverable prior state.</span><span class='qd'><b>Storing code only on one developer's laptop</b>: a single unmanaged copy provides no version history or resilience.</span>"},
  {"id":"D8-047","domain":8,"obj":"8.2","diff":"hard","q":"A CISSP reviews a pipeline that automatically deploys to production on every merge with no approval gate for sensitive changes. What is the BEST recommendation that preserves velocity while restoring control?","options":["Add automated policy-as-code gates plus a required approval for changes touching sensitive scopes, keeping routine changes automatic","Ban all automation and deploy manually","Deploy only once per year","Remove all testing from the pipeline"],"answer":0,"explain":"<strong>Add automated policy-as-code gates plus a required approval for changes touching sensitive scopes, keeping routine changes automatic</strong> balances speed with risk-based control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ban all automation and deploy manually</b>: manual-only deployment throws away CI/CD velocity unnecessarily.</span><span class='qd'><b>Deploy only once per year</b>: extreme batching increases risk per release and abandons continuous delivery.</span><span class='qd'><b>Remove all testing from the pipeline</b>: removing testing worsens quality and security, not control.</span>"},
  {"id":"D8-048","domain":8,"obj":"8.2","diff":"medium","q":"Which statement about SAST false positives and false negatives is MOST accurate?","options":["SAST has neither false positives nor false negatives","SAST always finds every vulnerability with perfect accuracy","SAST only produces false negatives, never false positives","SAST tends to produce false positives and can also miss issues (false negatives), so results require human triage"],"answer":3,"explain":"<strong>SAST tends to produce false positives and can also miss issues (false negatives), so results require human triage</strong> reflects the real accuracy tradeoffs of static analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST has neither false positives nor false negatives</b>: no tool is perfectly accurate; SAST has both.</span><span class='qd'><b>SAST always finds every vulnerability with perfect accuracy</b>: SAST cannot detect many runtime and logic flaws.</span><span class='qd'><b>SAST only produces false negatives, never false positives</b>: SAST is notably prone to false positives too.</span>"},
  {"id":"D8-049","domain":8,"obj":"8.3","diff":"medium","q":"An organization wants to assess whether its deployed application actually detects and records security-relevant events. Which activity is MOST directly relevant?","options":["Choosing new corporate logos","Measuring office temperature","Counting parking spaces","Reviewing audit logging coverage and testing that key events are captured and alertable"],"answer":3,"explain":"<strong>Reviewing audit logging coverage and testing that key events are captured and alertable</strong> directly assesses whether the application provides the accountability and detection expected.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choosing new corporate logos</b>: branding is unrelated to logging effectiveness.</span><span class='qd'><b>Measuring office temperature</b>: environmental measurement is irrelevant to software logging.</span><span class='qd'><b>Counting parking spaces</b>: facilities counts have nothing to do with audit logging.</span>"},
  {"id":"D8-050","domain":8,"obj":"8.3","diff":"easy","q":"Why should security-relevant application logs record who did what and when, and be protected from modification?","options":["To make logs harder to read","To increase CPU usage for its own sake","To replace the need for access control","To support accountability, non-repudiation, and reliable forensic reconstruction"],"answer":3,"explain":"<strong>To support accountability, non-repudiation, and reliable forensic reconstruction</strong> is why tamper-resistant, attributable logs matter for assessing and investigating software security.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make logs harder to read</b>: logs should be usable, not obfuscated.</span><span class='qd'><b>To increase CPU usage for its own sake</b>: consuming resources is not a logging objective.</span><span class='qd'><b>To replace the need for access control</b>: logging complements, but never replaces, access control.</span>"},
  {"id":"D8-051","domain":8,"obj":"8.3","diff":"medium","q":"During a software risk analysis, a team estimates likelihood and impact of each identified weakness to prioritize remediation. What is the PRIMARY benefit of this ranking?","options":["It guarantees zero vulnerabilities","It removes the need to patch anything","It focuses limited remediation resources on the highest-risk issues first","It makes all issues equally urgent"],"answer":2,"explain":"<strong>It focuses limited remediation resources on the highest-risk issues first</strong> is the value of risk-based prioritization, aligning effort with the greatest exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees zero vulnerabilities</b>: risk ranking prioritizes; it cannot guarantee elimination.</span><span class='qd'><b>It removes the need to patch anything</b>: analysis informs patching decisions, not their elimination.</span><span class='qd'><b>It makes all issues equally urgent</b>: the point is to differentiate urgency, not equalize it.</span>"},
  {"id":"D8-052","domain":8,"obj":"8.3","diff":"hard","q":"A CISSP must assess the effectiveness of security controls in a business-critical internal application before its annual reaccreditation. Which combination BEST provides defensible assurance?","options":["Independent testing (SAST/DAST/pen test), log/audit review, and mapping results to the risk register with sign-off","A single automated scan and nothing else","Only the developers' verbal assurance","Only reviewing the marketing brochure"],"answer":0,"explain":"<strong>Independent testing (SAST/DAST/pen test), log/audit review, and mapping results to the risk register with sign-off</strong> gives layered, documented, defensible assurance for reaccreditation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single automated scan and nothing else</b>: one scan is narrow and misses many control-effectiveness dimensions.</span><span class='qd'><b>Only the developers' verbal assurance</b>: unverified self-assurance is not defensible evidence.</span><span class='qd'><b>Only reviewing the marketing brochure</b>: marketing material provides no assurance of control effectiveness.</span>"},
  {"id":"D8-053","domain":8,"obj":"8.3","diff":"medium","q":"Which log-management weakness would MOST undermine an investigation of an application breach?","options":["Logs are centralized and time-synchronized","Logs are missing timestamps, unsynchronized, or writable by the same account that runs the app","Logs are retained for the required period","Logs are protected with integrity controls"],"answer":1,"explain":"<strong>Logs are missing timestamps, unsynchronized, or writable by the same account that runs the app</strong> would let events be untraceable or altered, crippling an investigation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Logs are centralized and time-synchronized</b>: this is a strength that aids investigation.</span><span class='qd'><b>Logs are retained for the required period</b>: proper retention supports, not undermines, investigation.</span><span class='qd'><b>Logs are protected with integrity controls</b>: integrity protection strengthens evidentiary value.</span>"},
  {"id":"D8-054","domain":8,"obj":"8.3","diff":"easy","q":"What is the purpose of code review as a software-security assessment technique?","options":["To make the code longer","To advertise the product","To manually or tool-assisted inspect source code for security flaws and logic errors","To measure server temperature"],"answer":2,"explain":"<strong>To manually or tool-assisted inspect source code for security flaws and logic errors</strong> is the purpose of code review, providing human insight into issues automation may miss.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the code longer</b>: review aims for quality, not verbosity.</span><span class='qd'><b>To advertise the product</b>: review is not a marketing activity.</span><span class='qd'><b>To measure server temperature</b>: environmental measurement is unrelated to code review.</span>"},
  {"id":"D8-055","domain":8,"obj":"8.3","diff":"hard","q":"An application logs full credit card numbers and passwords in plaintext to aid debugging. From a security-assessment standpoint, what is the MOST serious problem?","options":["The logs are too colorful","Sensitive data exposure: logging secrets and cardholder data violates data-protection requirements and creates a breach target","The logs are too short","The font used in the logs is wrong"],"answer":1,"explain":"<strong>Sensitive data exposure: logging secrets and cardholder data violates data-protection requirements and creates a breach target</strong> is the serious issue, breaching PCI DSS and privacy obligations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The logs are too colorful</b>: color is cosmetic and not a security problem.</span><span class='qd'><b>The logs are too short</b>: length is not the concern; the concern is exposing secrets.</span><span class='qd'><b>The font used in the logs is wrong</b>: font choice is irrelevant to data exposure.</span>"},
  {"id":"D8-056","domain":8,"obj":"8.3","diff":"medium","q":"To assess whether an application's security requirements were actually met, an assessor maps each requirement to a test that demonstrates it. This mapping is BEST called a:","options":["Marketing funnel","Requirements traceability matrix","Gantt chart of holidays","Random sampling of logos"],"answer":1,"explain":"<strong>Requirements traceability matrix</strong> links each requirement to design, code, and tests, letting an assessor confirm coverage and satisfaction of security requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Marketing funnel</b>: a marketing funnel models customer conversion, not requirement coverage.</span><span class='qd'><b>Gantt chart of holidays</b>: a holiday chart is a schedule artifact, not requirement tracing.</span><span class='qd'><b>Random sampling of logos</b>: sampling logos has nothing to do with requirement verification.</span>"},
  {"id":"D8-057","domain":8,"obj":"8.3","diff":"medium","q":"An organization measures software-security effectiveness using metrics. Which is the MOST meaningful outcome metric?","options":["Number of lines of code written per day","Number of coffee cups consumed","Mean time to remediate (MTTR) high-severity vulnerabilities and defect-escape rate to production","Count of meetings held"],"answer":2,"explain":"<strong>Mean time to remediate (MTTR) high-severity vulnerabilities and defect-escape rate to production</strong> are meaningful because they measure real security outcomes and process effectiveness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Number of lines of code written per day</b>: LOC is a vanity/output metric that does not reflect security effectiveness.</span><span class='qd'><b>Number of coffee cups consumed</b>: this is irrelevant to any security measure.</span><span class='qd'><b>Count of meetings held</b>: meeting counts do not indicate control effectiveness.</span>"},
  {"id":"D8-058","domain":8,"obj":"8.3","diff":"easy","q":"What is 'misuse case' analysis used for in software security assessment?","options":["Documenting intended features only","Choosing UI colors","Scheduling releases","Modeling how an attacker might abuse the system to identify needed countermeasures"],"answer":3,"explain":"<strong>Modeling how an attacker might abuse the system to identify needed countermeasures</strong> is the purpose of misuse (abuse) case analysis, the adversarial counterpart to use cases.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Documenting intended features only</b>: that is standard use-case analysis, not misuse cases.</span><span class='qd'><b>Choosing UI colors</b>: color selection is unrelated to abuse modeling.</span><span class='qd'><b>Scheduling releases</b>: scheduling is project management, not adversarial modeling.</span>"},
  {"id":"D8-059","domain":8,"obj":"8.3","diff":"hard","q":"After deployment, an application's control effectiveness is best kept current through which ongoing activity?","options":["A one-time assessment at go-live only","Assuming controls never degrade","Deleting the risk register after launch","Continuous monitoring, periodic reassessment, and re-testing after significant changes"],"answer":3,"explain":"<strong>Continuous monitoring, periodic reassessment, and re-testing after significant changes</strong> maintains assurance as threats, code, and configuration evolve over time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A one-time assessment at go-live only</b>: a single point-in-time check becomes stale as the system changes.</span><span class='qd'><b>Assuming controls never degrade</b>: controls do degrade and drift, so this assumption is unsafe.</span><span class='qd'><b>Deleting the risk register after launch</b>: destroying the risk record removes the basis for ongoing management.</span>"},
  {"id":"D8-060","domain":8,"obj":"8.3","diff":"medium","q":"Which is the BEST reason to include logging and monitoring requirements in the security assessment of an application?","options":["To fill space in the report","Because OWASP recognizes insufficient logging and monitoring as a top risk that delays breach detection","To reduce the number of controls","Because logs are never useful"],"answer":1,"explain":"<strong>Because OWASP recognizes insufficient logging and monitoring as a top risk that delays breach detection</strong> is why assessments must verify adequate logging and alerting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To fill space in the report</b>: logging assessment has substantive security value, not filler.</span><span class='qd'><b>To reduce the number of controls</b>: assessing logging does not aim to cut controls.</span><span class='qd'><b>Because logs are never useful</b>: logs are essential to detection and forensics.</span>"},
  {"id":"D8-061","domain":8,"obj":"8.3","diff":"easy","q":"In software risk analysis, 'residual risk' refers to:","options":["Risk that remains after controls have been applied","Risk that existed before the software was written","The total budget of the project","The number of developers on the team"],"answer":0,"explain":"<strong>Risk that remains after controls have been applied</strong> is the definition of residual risk, which management must accept, transfer, or further mitigate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk that existed before the software was written</b>: that is inherent risk, not residual.</span><span class='qd'><b>The total budget of the project</b>: budget is a financial figure, not a risk measure.</span><span class='qd'><b>The number of developers on the team</b>: staffing count is unrelated to residual risk.</span>"},
  {"id":"D8-062","domain":8,"obj":"8.3","diff":"medium","q":"A penetration test of a web application returns a list of exploitable findings. From a CISSP standpoint, what should happen NEXT with these findings?","options":["Ignore them until the next audit","Publish them publicly with exploit code","Delete the report to avoid liability","Risk-rank the findings, assign owners, and track remediation to closure in the risk register"],"answer":3,"explain":"<strong>Risk-rank the findings, assign owners, and track remediation to closure in the risk register</strong> turns test output into managed, accountable remediation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore them until the next audit</b>: ignoring exploitable findings leaves the organization exposed.</span><span class='qd'><b>Publish them publicly with exploit code</b>: public disclosure with exploits endangers the organization before fixes exist.</span><span class='qd'><b>Delete the report to avoid liability</b>: destroying evidence of known risk increases, not reduces, liability.</span>"},
  {"id":"D8-063","domain":8,"obj":"8.4","diff":"easy","q":"An organization is evaluating a commercial off-the-shelf (COTS) product to buy rather than build. Which security concern is MOST specific to COTS acquisition?","options":["You control every line of the vendor's source code","There is no licensing involved","You depend on the vendor for patches and cannot easily fix their code yourself","The software has no vulnerabilities by definition"],"answer":2,"explain":"<strong>You depend on the vendor for patches and cannot easily fix their code yourself</strong> is a core COTS concern because you inherit the vendor's security posture and patch cadence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>You control every line of the vendor's source code</b>: COTS source is typically closed, so you do not control it.</span><span class='qd'><b>There is no licensing involved</b>: COTS almost always involves licensing terms.</span><span class='qd'><b>The software has no vulnerabilities by definition</b>: all software can have vulnerabilities, COTS included.</span>"},
  {"id":"D8-064","domain":8,"obj":"8.4","diff":"medium","q":"Before adopting an open-source library, which review is MOST important to reduce security and legal risk?","options":["Reviewing the license terms, maintenance/community health, and known vulnerabilities (CVEs)","Only checking the project's logo","Counting the number of stars only","Assuming open source is always safe"],"answer":0,"explain":"<strong>Reviewing the license terms, maintenance/community health, and known vulnerabilities (CVEs)</strong> addresses both legal compatibility and security risk of adopting the component.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only checking the project's logo</b>: a logo tells you nothing about security or licensing.</span><span class='qd'><b>Counting the number of stars only</b>: popularity alone does not reveal vulnerabilities or license risk.</span><span class='qd'><b>Assuming open source is always safe</b>: open source can contain serious vulnerabilities and restrictive licenses.</span>"},
  {"id":"D8-065","domain":8,"obj":"8.4","diff":"hard","q":"A company is signing a contract for a critical SaaS provider. Which contractual/assessment element MOST directly protects the company's ability to verify the provider's security over time?","options":["Right-to-audit or independent attestation (e.g., SOC 2), security SLAs, and breach-notification obligations","A clause forbidding the company from ever asking questions","A promise with no evidence requirement","Removing all security requirements to speed signing"],"answer":0,"explain":"<strong>Right-to-audit or independent attestation (e.g., SOC 2), security SLAs, and breach-notification obligations</strong> gives ongoing, evidence-based assurance and accountability from the SaaS provider.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A clause forbidding the company from ever asking questions</b>: barring inquiry removes the ability to verify security.</span><span class='qd'><b>A promise with no evidence requirement</b>: unverifiable promises provide no real assurance.</span><span class='qd'><b>Removing all security requirements to speed signing</b>: dropping requirements abandons due diligence.</span>"},
  {"id":"D8-066","domain":8,"obj":"8.4","diff":"medium","q":"What is a Software Bill of Materials (SBOM) and why is it valuable when acquiring third-party software?","options":["An inventory of components and dependencies; it lets you assess vulnerabilities in what you are consuming","A price list; it shows the cost of the software","A user manual; it explains how to click buttons","A marketing flyer; it advertises features"],"answer":0,"explain":"<strong>An inventory of components and dependencies; it lets you assess vulnerabilities in what you are consuming</strong> is what an SBOM provides, enabling rapid impact analysis when a component CVE appears.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A price list; it shows the cost of the software</b>: an SBOM lists components, not prices.</span><span class='qd'><b>A user manual; it explains how to click buttons</b>: usage instructions are not a component inventory.</span><span class='qd'><b>A marketing flyer; it advertises features</b>: marketing material is not a bill of materials.</span>"},
  {"id":"D8-067","domain":8,"obj":"8.4","diff":"easy","q":"Which activity BEST describes vendor security due diligence before acquiring third-party software?","options":["Signing immediately without any review","Choosing the cheapest option regardless of security","Evaluating the vendor's security practices, certifications, patch history, and financial stability before purchase","Relying solely on the vendor's advertising"],"answer":2,"explain":"<strong>Evaluating the vendor's security practices, certifications, patch history, and financial stability before purchase</strong> is proper due diligence to understand inherited risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signing immediately without any review</b>: skipping review forgoes due diligence entirely.</span><span class='qd'><b>Choosing the cheapest option regardless of security</b>: cost-only selection ignores security risk.</span><span class='qd'><b>Relying solely on the vendor's advertising</b>: advertising is not independent evidence of security.</span>"},
  {"id":"D8-068","domain":8,"obj":"8.4","diff":"hard","q":"An acquired COTS product will process regulated personal data. Which step MOST directly addresses the residual risk that the vendor mishandles that data?","options":["Assume the vendor complies because they are large","Establish a data processing agreement with defined controls, and validate through attestation or audit and breach-notification terms","Give the vendor unrestricted access to all systems","Remove all contract terms to simplify"],"answer":1,"explain":"<strong>Establish a data processing agreement with defined controls, and validate through attestation or audit and breach-notification terms</strong> binds the vendor to specific obligations and provides verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the vendor complies because they are large</b>: size is not evidence of compliance.</span><span class='qd'><b>Give the vendor unrestricted access to all systems</b>: excessive access increases risk rather than controlling it.</span><span class='qd'><b>Remove all contract terms to simplify</b>: removing terms strips away the controls and recourse you need.</span>"},
  {"id":"D8-069","domain":8,"obj":"8.4","diff":"medium","q":"A team wants to reduce the risk of a malicious or abandoned open-source dependency slipping into production. Which control is MOST effective?","options":["Vet and pin approved versions from a curated internal repository and continuously scan for new CVEs and maintainer changes","Pull the latest version of any package automatically at every build","Never update dependencies at all","Trust any package with a nice README"],"answer":0,"explain":"<strong>Vet and pin approved versions from a curated internal repository and continuously scan for new CVEs and maintainer changes</strong> controls provenance and detects emerging risk in dependencies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pull the latest version of any package automatically at every build</b>: auto-pulling unvetted latest versions invites malicious or breaking updates.</span><span class='qd'><b>Never update dependencies at all</b>: never updating leaves known vulnerabilities unpatched.</span><span class='qd'><b>Trust any package with a nice README</b>: documentation quality is no indicator of security.</span>"},
  {"id":"D8-070","domain":8,"obj":"8.4","diff":"easy","q":"Which is a defining trait of Software as a Service (SaaS) from a security-responsibility standpoint?","options":["The provider manages the application and infrastructure while the customer mainly manages data, access, and configuration","The customer patches the underlying operating system","The customer owns the provider's data center","There is no shared responsibility at all"],"answer":0,"explain":"<strong>The provider manages the application and infrastructure while the customer mainly manages data, access, and configuration</strong> reflects the SaaS shared-responsibility split.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The customer patches the underlying operating system</b>: in SaaS the provider handles OS patching, not the customer.</span><span class='qd'><b>The customer owns the provider's data center</b>: the provider owns and operates the infrastructure.</span><span class='qd'><b>There is no shared responsibility at all</b>: SaaS still has a shared-responsibility model.</span>"},
  {"id":"D8-071","domain":8,"obj":"8.4","diff":"hard","q":"During acquisition of third-party software, an escrow agreement is proposed. What risk does source-code escrow MOST directly mitigate?","options":["The risk that the vendor goes out of business or stops support, leaving the buyer unable to maintain critical software","The risk that the software is too colorful","The risk of high electricity bills","The risk of slow typing"],"answer":0,"explain":"<strong>The risk that the vendor goes out of business or stops support, leaving the buyer unable to maintain critical software</strong> is exactly what source-code escrow addresses by releasing code under defined trigger conditions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The risk that the software is too colorful</b>: appearance is not a business-continuity risk.</span><span class='qd'><b>The risk of high electricity bills</b>: energy cost is unrelated to escrow.</span><span class='qd'><b>The risk of slow typing</b>: typing speed has nothing to do with vendor viability.</span>"},
  {"id":"D8-072","domain":8,"obj":"8.4","diff":"medium","q":"A vendor's COTS product cannot be independently source-reviewed. Which assessment approach is MOST appropriate to gain assurance?","options":["Assume it is secure and skip testing","Demand the vendor's trade-secret algorithms be published","Perform black-box testing (DAST/pen test) against a representative deployment and require independent attestations","Do nothing because it is a purchase"],"answer":2,"explain":"<strong>Perform black-box testing (DAST/pen test) against a representative deployment and require independent attestations</strong> gains assurance without source access, which is realistic for closed COTS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume it is secure and skip testing</b>: assumption provides no assurance.</span><span class='qd'><b>Demand the vendor's trade-secret algorithms be published</b>: vendors will not disclose trade secrets, so this is unworkable.</span><span class='qd'><b>Do nothing because it is a purchase</b>: acquisition still requires assessment of inherited risk.</span>"},
  {"id":"D8-073","domain":8,"obj":"8.4","diff":"medium","q":"Why is continuous monitoring of third-party and open-source components important AFTER they are adopted?","options":["Because new vulnerabilities (CVEs) are disclosed over time in components that were safe when adopted","Because components never change once adopted","Because monitoring lowers the software's price","Because monitoring replaces the need for any contracts"],"answer":0,"explain":"<strong>Because new vulnerabilities (CVEs) are disclosed over time in components that were safe when adopted</strong> is why ongoing monitoring is essential; risk is not static.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because components never change once adopted</b>: the threat landscape and the components both change over time.</span><span class='qd'><b>Because monitoring lowers the software's price</b>: monitoring is about risk, not cost reduction.</span><span class='qd'><b>Because monitoring replaces the need for any contracts</b>: monitoring complements contracts; it does not replace them.</span>"},
  {"id":"D8-074","domain":8,"obj":"8.4","diff":"easy","q":"What is a PRIMARY licensing risk when using open-source software in a commercial product?","options":["A copyleft license (e.g., GPL) may require you to release your own source code under the same terms","The code will always crash","Open source cannot be downloaded","Licenses are irrelevant to software"],"answer":0,"explain":"<strong>A copyleft license (e.g., GPL) may require you to release your own source code under the same terms</strong> is a key legal risk of incorporating certain open-source components.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The code will always crash</b>: license type does not cause crashes.</span><span class='qd'><b>Open source cannot be downloaded</b>: open source is by definition downloadable.</span><span class='qd'><b>Licenses are irrelevant to software</b>: licenses govern legal use and are highly relevant.</span>"},
  {"id":"D8-075","domain":8,"obj":"8.4","diff":"hard","q":"A CISSP is asked to approve integrating a free third-party JavaScript widget loaded directly from the vendor's CDN into the company's checkout page. What is the BEST risk-based recommendation?","options":["Reject direct external loading; self-host a vetted, version-pinned copy with Subresource Integrity and monitoring, given the payment context","Approve it as-is because it is free","Load it and disable all logging","Approve it only if it looks nice"],"answer":0,"explain":"<strong>Reject direct external loading; self-host a vetted, version-pinned copy with Subresource Integrity and monitoring, given the payment context</strong> mitigates supply-chain and Magecart-style risk on a sensitive checkout page.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Approve it as-is because it is free</b>: cost is irrelevant to the supply-chain risk of externally loaded code on a payment page.</span><span class='qd'><b>Load it and disable all logging</b>: disabling logging removes detection while adding risky external code.</span><span class='qd'><b>Approve it only if it looks nice</b>: appearance is not a security criterion.</span>"},
  {"id":"D8-076","domain":8,"obj":"8.4","diff":"medium","q":"When acquiring software, which artifact BEST helps a buyer quickly determine exposure to a newly announced dependency vulnerability?","options":["The vendor's marketing deck","A current Software Bill of Materials (SBOM) for the product","The vendor's holiday schedule","A photo of the development team"],"answer":1,"explain":"<strong>A current Software Bill of Materials (SBOM) for the product</strong> lets a buyer instantly check whether the affected component is present and where.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The vendor's marketing deck</b>: marketing does not list components or versions.</span><span class='qd'><b>The vendor's holiday schedule</b>: a calendar reveals nothing about dependency exposure.</span><span class='qd'><b>A photo of the development team</b>: personnel photos give no component information.</span>"},
  {"id":"D8-077","domain":8,"obj":"8.5","diff":"easy","q":"An attacker submits <script>alert(1)</script> into a comment field and it executes in other users' browsers. Which OWASP vulnerability is this?","options":["SQL Injection","Buffer overflow","Cross-Site Scripting (XSS)","Broken cryptography"],"answer":2,"explain":"<strong>Cross-Site Scripting (XSS)</strong> occurs when untrusted input is rendered as executable script in a victim's browser, as this stored-comment example shows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL Injection</b>: SQL injection targets a database query, not script execution in the browser.</span><span class='qd'><b>Buffer overflow</b>: buffer overflow corrupts memory in native code, not browser-rendered script.</span><span class='qd'><b>Broken cryptography</b>: broken crypto concerns weak encryption, not injected client-side script.</span>"},
  {"id":"D8-078","domain":8,"obj":"8.5","diff":"easy","q":"A login form builds a query as \"SELECT * FROM users WHERE name='\" + input + \"'\". Entering ' OR '1'='1 bypasses login. What is the vulnerability and the BEST fix?","options":["Buffer overflow; add more RAM","XSS; change the font","CSRF; disable cookies entirely","SQL Injection; use parameterized queries/prepared statements"],"answer":3,"explain":"<strong>SQL Injection; use parameterized queries/prepared statements</strong> is correct because concatenating input into SQL lets attackers alter query logic, and parameterization separates code from data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buffer overflow; add more RAM</b>: this is injection, not a memory-overflow issue, and RAM is irrelevant.</span><span class='qd'><b>XSS; change the font</b>: the flaw is in the SQL query, not browser rendering, and fonts are irrelevant.</span><span class='qd'><b>CSRF; disable cookies entirely</b>: CSRF is a different class of attack and disabling cookies does not fix injection.</span>"},
  {"id":"D8-079","domain":8,"obj":"8.5","diff":"medium","q":"A banking site lets a logged-in user's browser be tricked by a malicious page into submitting a funds-transfer request the user did not intend. Which vulnerability is this, and what is the BEST defense?","options":["SQL injection; add indexes","XSS; increase password length","Cross-Site Request Forgery (CSRF); use anti-CSRF tokens and SameSite cookies","Buffer overflow; recompile the OS"],"answer":2,"explain":"<strong>Cross-Site Request Forgery (CSRF); use anti-CSRF tokens and SameSite cookies</strong> is correct because CSRF abuses the victim's authenticated session, and unpredictable tokens plus SameSite cookies defeat forged cross-site requests.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL injection; add indexes</b>: this is a session-riding attack, and indexes are a performance feature.</span><span class='qd'><b>XSS; increase password length</b>: XSS is script injection, and password length does not stop forged requests.</span><span class='qd'><b>Buffer overflow; recompile the OS</b>: CSRF is not a memory-safety bug, and recompiling the OS is irrelevant.</span>"},
  {"id":"D8-080","domain":8,"obj":"8.5","diff":"medium","q":"A C program copies user input into a fixed 64-byte stack buffer using strcpy with no length check, allowing an attacker to overwrite the return address. What is this classic vulnerability?","options":["SQL injection","Cross-site scripting","Buffer overflow","Clickjacking"],"answer":2,"explain":"<strong>Buffer overflow</strong> occurs when input exceeds a fixed buffer and overwrites adjacent memory such as the return address, enabling code execution; bounds-checked functions prevent it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL injection</b>: SQL injection manipulates database queries, not stack memory.</span><span class='qd'><b>Cross-site scripting</b>: XSS executes script in browsers, not native stack memory corruption.</span><span class='qd'><b>Clickjacking</b>: clickjacking tricks users into clicking hidden UI, unrelated to memory overwrites.</span>"},
  {"id":"D8-081","domain":8,"obj":"8.5","diff":"medium","q":"According to secure coding principles, what is the MOST reliable general defense against injection attacks (SQL, LDAP, OS command)?","options":["Client-side validation only","Hiding the form fields with CSS","Never trusting input: use parameterized interfaces and context-appropriate input validation/output encoding on the server","Using a longer session timeout"],"answer":2,"explain":"<strong>Never trusting input: use parameterized interfaces and context-appropriate input validation/output encoding on the server</strong> is the general defense, keeping untrusted data from being interpreted as code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Client-side validation only</b>: client checks are trivially bypassed and cannot be trusted for security.</span><span class='qd'><b>Hiding the form fields with CSS</b>: hiding fields does not stop crafted requests to the server.</span><span class='qd'><b>Using a longer session timeout</b>: session duration is unrelated to injection defense.</span>"},
  {"id":"D8-082","domain":8,"obj":"8.5","diff":"easy","q":"What is the PRIMARY purpose of output encoding (e.g., HTML-encoding untrusted data) in web applications?","options":["To make pages load faster","To compress images","To ensure untrusted data is rendered as inert text rather than executed as markup or script, preventing XSS","To sort database rows"],"answer":2,"explain":"<strong>To ensure untrusted data is rendered as inert text rather than executed as markup or script, preventing XSS</strong> is the purpose of context-aware output encoding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make pages load faster</b>: encoding is a security measure, not a performance optimization.</span><span class='qd'><b>To compress images</b>: encoding untrusted text is unrelated to image compression.</span><span class='qd'><b>To sort database rows</b>: sorting is a data operation, not an XSS defense.</span>"},
  {"id":"D8-083","domain":8,"obj":"8.5","diff":"hard","q":"An API endpoint returns a user's record if the request includes an account ID in the URL, and an attacker simply changes the ID to view other users' data. Which OWASP API risk is this?","options":["Buffer overflow","Broken Object Level Authorization (BOLA/IDOR)","Cross-site scripting","Weak TLS ciphers"],"answer":1,"explain":"<strong>Broken Object Level Authorization (BOLA/IDOR)</strong> occurs when the API fails to verify that the caller is authorized for the specific object referenced, letting attackers enumerate others' records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buffer overflow</b>: this is an authorization flaw, not memory corruption.</span><span class='qd'><b>Cross-site scripting</b>: XSS involves script execution in a browser, not object-level access control.</span><span class='qd'><b>Weak TLS ciphers</b>: weak ciphers concern transport encryption, not per-object authorization.</span>"},
  {"id":"D8-084","domain":8,"obj":"8.5","diff":"medium","q":"Which practice BEST reflects the secure-coding principle of 'fail securely'?","options":["On an unexpected error, grant access to keep the app usable","On an unexpected error, deny the action and log it rather than defaulting to open","Display full stack traces to end users","Silently ignore all exceptions"],"answer":1,"explain":"<strong>On an unexpected error, deny the action and log it rather than defaulting to open</strong> embodies failing securely, ensuring errors do not bypass controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>On an unexpected error, grant access to keep the app usable</b>: defaulting to open is fail-open, the insecure opposite.</span><span class='qd'><b>Display full stack traces to end users</b>: leaking stack traces reveals internal details to attackers.</span><span class='qd'><b>Silently ignore all exceptions</b>: swallowing exceptions hides failures and can leave the system in an unsafe state.</span>"},
  {"id":"D8-085","domain":8,"obj":"8.5","diff":"easy","q":"What does the OWASP Top 10 represent?","options":["A widely referenced awareness list of the most critical web application security risks","The ten fastest programming languages","A list of the ten largest software vendors","A ranking of the best IDEs"],"answer":0,"explain":"<strong>A widely referenced awareness list of the most critical web application security risks</strong> is what the OWASP Top 10 is, guiding developers on prevalent, high-impact issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The ten fastest programming languages</b>: OWASP does not rank language speed.</span><span class='qd'><b>A list of the ten largest software vendors</b>: it is not a vendor ranking.</span><span class='qd'><b>A ranking of the best IDEs</b>: OWASP Top 10 is about risks, not tools.</span>"},
  {"id":"D8-086","domain":8,"obj":"8.5","diff":"hard","q":"An application deserializes user-supplied objects without validation, and a crafted payload triggers remote code execution. Which secure-coding guidance MOST directly prevents this?","options":["Increase the page cache size","Use a bigger font on error pages","Avoid deserializing untrusted data, or use safe formats/allowlists and integrity checks","Enable more verbose stack traces for users"],"answer":2,"explain":"<strong>Avoid deserializing untrusted data, or use safe formats/allowlists and integrity checks</strong> directly addresses insecure deserialization, which can lead to RCE.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the page cache size</b>: caching is unrelated to deserialization safety.</span><span class='qd'><b>Use a bigger font on error pages</b>: styling does not affect object deserialization.</span><span class='qd'><b>Enable more verbose stack traces for users</b>: exposing stack traces helps attackers and does not prevent RCE.</span>"},
  {"id":"D8-087","domain":8,"obj":"8.5","diff":"medium","q":"An API has no rate limiting, allowing attackers to brute-force credentials and scrape data at high volume. Which control MOST directly addresses this OWASP API risk?","options":["Removing all authentication","Returning larger responses","Disabling TLS to save bandwidth","Implementing rate limiting/throttling and resource quotas per client"],"answer":3,"explain":"<strong>Implementing rate limiting/throttling and resource quotas per client</strong> mitigates unrestricted resource consumption and abuse such as credential brute-forcing and scraping.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Removing all authentication</b>: removing authentication makes abuse easier, not harder.</span><span class='qd'><b>Returning larger responses</b>: larger responses increase, not reduce, the abuse impact.</span><span class='qd'><b>Disabling TLS to save bandwidth</b>: disabling TLS exposes traffic and does nothing about rate abuse.</span>"},
  {"id":"D8-088","domain":8,"obj":"8.5","diff":"medium","q":"Which secure-coding practice BEST reduces the impact of a compromised application component (defense in depth)?","options":["Run every process as root/administrator","Grant broad database rights to simplify code","Disable all access controls in development and production alike","Apply least privilege so each component runs with only the permissions it needs"],"answer":3,"explain":"<strong>Apply least privilege so each component runs with only the permissions it needs</strong> limits what an attacker gains if a component is compromised.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run every process as root/administrator</b>: maximal privilege maximizes blast radius on compromise.</span><span class='qd'><b>Grant broad database rights to simplify code</b>: excessive DB rights let an injection flaw do far more damage.</span><span class='qd'><b>Disable all access controls in development and production alike</b>: removing access controls eliminates defense in depth.</span>"},
  {"id":"D8-089","domain":8,"obj":"8.5","diff":"hard","q":"A REST API accepts a JWT but does not verify the token's signature, trusting the 'alg: none' header. What is the vulnerability and BEST remediation?","options":["It is fine; JWTs are always secure","Buffer overflow; add more memory","XSS; encode the token","Broken authentication via unverified token; enforce signature verification, reject 'none', and validate issuer/audience/expiry"],"answer":3,"explain":"<strong>Broken authentication via unverified token; enforce signature verification, reject 'none', and validate issuer/audience/expiry</strong> fixes the flaw of trusting an unsigned or attacker-controlled token.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is fine; JWTs are always secure</b>: an unverified 'alg:none' token is trivially forgeable.</span><span class='qd'><b>Buffer overflow; add more memory</b>: this is an authentication flaw, not memory corruption.</span><span class='qd'><b>XSS; encode the token</b>: the issue is signature verification, not output encoding.</span>"},
  {"id":"D8-090","domain":8,"obj":"8.5","diff":"easy","q":"Why is server-side input validation required even when client-side validation exists?","options":["Because client-side validation looks nicer","Because attackers can bypass the client entirely and send crafted requests directly to the server","Because it makes the page load slower","Because servers cannot validate input"],"answer":1,"explain":"<strong>Because attackers can bypass the client entirely and send crafted requests directly to the server</strong> is why authoritative validation must occur server-side.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because client-side validation looks nicer</b>: appearance is not a security reason.</span><span class='qd'><b>Because it makes the page load slower</b>: performance is not the rationale.</span><span class='qd'><b>Because servers cannot validate input</b>: servers can and must validate input.</span>"},
  {"id":"D8-091","domain":8,"obj":"8.5","diff":"medium","q":"An application stores user passwords using unsalted MD5. What is the BEST secure-coding remediation?","options":["Keep MD5 but make passwords shorter","Store passwords in plaintext for easy recovery","Encrypt passwords with a hard-coded key in the source","Store passwords using a slow, salted adaptive hash such as bcrypt, scrypt, or Argon2"],"answer":3,"explain":"<strong>Store passwords using a slow, salted adaptive hash such as bcrypt, scrypt, or Argon2</strong> resists brute-force and rainbow-table attacks that fast unsalted MD5 cannot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keep MD5 but make passwords shorter</b>: MD5 is fast and broken for this use, and shorter passwords are weaker.</span><span class='qd'><b>Store passwords in plaintext for easy recovery</b>: plaintext storage is a severe exposure.</span><span class='qd'><b>Encrypt passwords with a hard-coded key in the source</b>: hard-coded keys are recoverable, and reversible encryption is inappropriate for password verification.</span>"},
  {"id":"D8-092","domain":8,"obj":"8.5","diff":"hard","q":"A web app builds an OS command from user input to ping a host by concatenating the raw input into a shell string. An attacker enters '127.0.0.1; rm -rf /'. Which vulnerability class is this and the BEST fix?","options":["XSS; HTML-encode the output","CSRF; add a token","Buffer overflow; increase the stack size","OS command injection; avoid shell calls, use safe APIs, and strictly validate/allowlist input"],"answer":3,"explain":"<strong>OS command injection; avoid shell calls, use safe APIs, and strictly validate/allowlist input</strong> is correct because concatenating input into a shell command lets attackers run arbitrary commands.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>XSS; HTML-encode the output</b>: this executes on the server shell, not in a browser, so encoding does not fix it.</span><span class='qd'><b>CSRF; add a token</b>: CSRF is a different attack; a token does not stop command injection.</span><span class='qd'><b>Buffer overflow; increase the stack size</b>: this is injection, not a memory overflow, and stack size is irrelevant.</span>"},
  {"id":"D8-093","domain":8,"obj":"8.5","diff":"medium","q":"Which control BEST mitigates reflected and stored XSS as a defense-in-depth layer in the browser?","options":["Disabling HTTPS","Removing all input fields","A restrictive Content Security Policy (CSP) plus context-aware output encoding","Increasing the session cookie lifetime"],"answer":2,"explain":"<strong>A restrictive Content Security Policy (CSP) plus context-aware output encoding</strong> both prevents injected script from being rendered and constrains what scripts the browser will execute.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling HTTPS</b>: removing transport encryption harms security and does not stop XSS.</span><span class='qd'><b>Removing all input fields</b>: eliminating inputs is impractical and not a real defense strategy.</span><span class='qd'><b>Increasing the session cookie lifetime</b>: longer sessions increase exposure and do not mitigate XSS.</span>"},
  {"id":"D8-094","domain":8,"obj":"8.5","diff":"easy","q":"What is the secure-coding principle of 'defense in depth'?","options":["Layering multiple independent controls so failure of one does not lead to compromise","Relying on a single strong control","Removing controls to improve speed","Trusting the network perimeter entirely"],"answer":0,"explain":"<strong>Layering multiple independent controls so failure of one does not lead to compromise</strong> is the essence of defense in depth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Relying on a single strong control</b>: single-control reliance is the opposite of layered defense.</span><span class='qd'><b>Removing controls to improve speed</b>: removing controls reduces, not deepens, defense.</span><span class='qd'><b>Trusting the network perimeter entirely</b>: perimeter-only trust ignores internal and application-layer threats.</span>"},
  {"id":"D8-095","domain":8,"obj":"8.5","diff":"hard","q":"An API returns verbose error messages containing SQL statements, internal file paths, and framework versions to clients. From a secure-coding view, what is the BEST remediation?","options":["Add more detail to error messages for clarity","Return generic error messages to clients while logging full details securely server-side","Disable logging entirely","Show the database password to authenticated users only"],"answer":1,"explain":"<strong>Return generic error messages to clients while logging full details securely server-side</strong> prevents information leakage that aids attackers while preserving diagnostic data for defenders.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add more detail to error messages for clarity</b>: more detail worsens the information-disclosure problem.</span><span class='qd'><b>Disable logging entirely</b>: disabling logging removes needed diagnostics and detection.</span><span class='qd'><b>Show the database password to authenticated users only</b>: exposing credentials to any users is a severe risk.</span>"},
  {"id":"D8-096","domain":8,"obj":"8.5","diff":"medium","q":"Which is the MOST appropriate use of an allowlist (whitelist) in input validation?","options":["Blocking only known-bad characters and allowing everything else","Defining exactly what valid input is permitted and rejecting anything that does not match","Allowing all input to maximize compatibility","Validating input only on the client"],"answer":1,"explain":"<strong>Defining exactly what valid input is permitted and rejecting anything that does not match</strong> is allowlisting, which is more robust than trying to enumerate all bad input.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blocking only known-bad characters and allowing everything else</b>: denylisting misses novel or encoded malicious input.</span><span class='qd'><b>Allowing all input to maximize compatibility</b>: accepting all input defeats validation entirely.</span><span class='qd'><b>Validating input only on the client</b>: client-only validation is bypassable and untrustworthy.</span>"},
  {"id":"D8-097","domain":8,"obj":"8.5","diff":"medium","q":"An organization is designing API security. Which combination BEST enforces that only authorized callers can invoke sensitive operations?","options":["No authentication, relying on obscure URLs","Only client-side JavaScript checks","A single shared API key printed in the mobile app binary","Strong authentication (e.g., OAuth 2.0), per-request authorization checks, and TLS for transport"],"answer":3,"explain":"<strong>Strong authentication (e.g., OAuth 2.0), per-request authorization checks, and TLS for transport</strong> together enforce identity, authorization, and confidentiality for API calls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>No authentication, relying on obscure URLs</b>: security through obscurity fails once a URL is discovered.</span><span class='qd'><b>Only client-side JavaScript checks</b>: client checks are bypassable and provide no server-side enforcement.</span><span class='qd'><b>A single shared API key printed in the mobile app binary</b>: an embedded static key can be extracted and reused by anyone.</span>"},
  {"id":"D8-098","domain":8,"obj":"8.5","diff":"hard","q":"A microservice trusts requests from other internal services without verifying them, assuming the network is safe. An attacker who breaches one service can now call any other. Which principle should the design adopt?","options":["Implicit trust of the internal network","Zero trust: authenticate and authorize every service-to-service call regardless of network location","Disable all internal encryption","Give every service full admin rights"],"answer":1,"explain":"<strong>Zero trust: authenticate and authorize every service-to-service call regardless of network location</strong> removes the flawed assumption that internal traffic is inherently safe.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Implicit trust of the internal network</b>: implicit trust is exactly the assumption that enabled lateral movement.</span><span class='qd'><b>Disable all internal encryption</b>: removing encryption increases exposure of internal traffic.</span><span class='qd'><b>Give every service full admin rights</b>: broad admin rights maximize the impact of any single compromise.</span>"},
  {"id":"D8-099","domain":8,"obj":"8.5","diff":"medium","q":"During secure code review, a developer finds that user-controlled data flows into a file path used to read files (e.g., ../../etc/passwd). Which vulnerability is this and the BEST fix?","options":["SQL injection; parameterize the query","Path/directory traversal; canonicalize and validate paths against an allowlisted base directory","XSS; encode HTML output","CSRF; add a synchronizer token"],"answer":1,"explain":"<strong>Path/directory traversal; canonicalize and validate paths against an allowlisted base directory</strong> is correct because traversal sequences let attackers escape the intended directory, and canonicalization plus a confined base stops it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL injection; parameterize the query</b>: the flaw is file-path handling, not a database query.</span><span class='qd'><b>XSS; encode HTML output</b>: this reads server files, not browser rendering.</span><span class='qd'><b>CSRF; add a synchronizer token</b>: CSRF is unrelated to traversing the file system.</span>"},
  {"id":"D8-100","domain":8,"obj":"8.5","diff":"hard","q":"A CISSP wants to institutionalize secure coding across many teams rather than relying on individual heroics. Which combination is the MOST effective, program-level approach?","options":["Hope developers remember best practices","Ban all third-party libraries permanently","Perform one annual training with no tooling","Adopt secure coding standards, provide training and security champions, and enforce automated guardrails (SAST/SCA) in the pipeline"],"answer":3,"explain":"<strong>Adopt secure coding standards, provide training and security champions, and enforce automated guardrails (SAST/SCA) in the pipeline</strong> combines people, process, and technology for durable, scalable secure development.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hope developers remember best practices</b>: hope is not a control and does not scale.</span><span class='qd'><b>Ban all third-party libraries permanently</b>: a blanket ban is impractical and forgoes vetted, valuable components.</span><span class='qd'><b>Perform one annual training with no tooling</b>: annual-only training without automation leaves day-to-day code unguarded.</span>"}
);
